+                    ('dt', 10.0, 1.0, 0.0, null, null, null),
+                    (null, null, null, null, 1.0, null, null)
+                """);
+
+        // Verify only one row exists (confirming overwrite, not append)
+        assertQuery("SELECT COUNT(*) FROM " + testTable, "VALUES 1");
